-- table: races
CREATE TABLE races (
  id INTEGER PRIMARY KEY AUTOINCREMENT,

  -- Natural identifiers
  race_date TEXT NOT NULL,
  venue_id INTEGER NOT NULL,
  race_no INTEGER NOT NULL,

  -- Race information
  race_name TEXT,
  grade TEXT,
  distance_m INTEGER DEFAULT 1800,
  deadline_at TEXT,
  start_at TEXT,

  -- Conditions
  weather TEXT,
  wind_direction TEXT,
  wind_speed_m REAL,
  wave_height_cm REAL,
  temperature_c REAL,
  water_temperature_c REAL,
  water_line TEXT,
  is_stabilizer_used INTEGER NOT NULL DEFAULT 0,
  is_fixed_entry INTEGER NOT NULL DEFAULT 0,

  -- Status
  status TEXT NOT NULL DEFAULT 'scheduled',
  source_url TEXT,

  created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP, distance INTEGER, start_time TEXT, wind_speed REAL, water_temperature REAL, wave_height INTEGER,

  FOREIGN KEY (venue_id) REFERENCES venues(id),

  UNIQUE (race_date, venue_id, race_no),

  CHECK (race_no BETWEEN 1 AND 12),
  CHECK (is_stabilizer_used IN (0, 1)),
  CHECK (is_fixed_entry IN (0, 1))
);

