-- view: v_prediction_run_summary
CREATE VIEW v_prediction_run_summary AS
SELECT
  pr.id AS prediction_run_id,
  pr.run_key,
  pr.target_date,
  pr.executed_at,
  pr.model_name,
  pr.model_version,
  COUNT(DISTINCT p.race_id) AS race_count,
  COUNT(t.id) AS ticket_count,
  COALESCE(SUM(t.amount), 0) AS total_amount,
  COALESCE(SUM(t.payout_amount), 0) AS total_payout,
  COALESCE(SUM(t.payout_amount), 0) - COALESCE(SUM(t.amount), 0) AS total_profit,
  CASE
    WHEN COALESCE(SUM(t.amount), 0) = 0 THEN NULL
    ELSE ROUND(COALESCE(SUM(t.payout_amount), 0) * 100.0 / SUM(t.amount), 2)
  END AS return_rate_percent,
  CASE
    WHEN COUNT(t.id) = 0 THEN NULL
    ELSE ROUND(SUM(CASE WHEN t.is_hit = 1 THEN 1 ELSE 0 END) * 100.0 / COUNT(t.id), 2)
  END AS hit_rate_percent
FROM prediction_runs pr
LEFT JOIN predictions p
  ON p.prediction_run_id = pr.id
LEFT JOIN prediction_tickets t
  ON t.prediction_id = p.id
GROUP BY
  pr.id,
  pr.run_key,
  pr.target_date,
  pr.executed_at,
  pr.model_name,
  pr.model_version;

-- view: v_prediction_ticket_results
CREATE VIEW v_prediction_ticket_results AS
SELECT
  pr.id AS prediction_run_id,
  pr.run_key,
  pr.target_date,
  pr.model_name,
  pr.model_version,
  p.id AS prediction_id,
  p.race_id,
  t.id AS ticket_id,
  t.bet_type,
  t.combination,
  t.amount,
  t.estimated_probability,
  t.expected_odds,
  t.expected_value,
  t.is_hit,
  t.payout_amount,
  t.profit_amount
FROM prediction_runs pr
JOIN predictions p
  ON p.prediction_run_id = pr.id
JOIN prediction_tickets t
  ON t.prediction_id = p.id;

-- view: v_race_overview
CREATE VIEW v_race_overview AS
SELECT
  r.id AS race_id,
  r.race_date,
  v.venue_code,
  v.venue_name,
  r.race_no,
  r.race_name,
  r.grade,
  r.deadline_at,
  r.start_at,
  r.status,
  r.weather,
  r.wind_speed_m,
  r.wave_height_cm,
  r.temperature_c,
  r.water_temperature_c
FROM races r
JOIN venues v
  ON r.venue_id = v.id;


-- STEP109: prediction run history
CREATE TABLE IF NOT EXISTS prediction_runs (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    run_key TEXT NOT NULL UNIQUE,
    model_name TEXT NOT NULL,
    model_version TEXT NOT NULL,
    target_date TEXT NOT NULL,
    started_at TEXT,
    finished_at TEXT,
    status TEXT NOT NULL DEFAULT 'completed',
    race_count INTEGER NOT NULL DEFAULT 0,
    recommendation_count INTEGER NOT NULL DEFAULT 0,
    high_ev_count INTEGER NOT NULL DEFAULT 0,
    alert_count INTEGER NOT NULL DEFAULT 0,
    quality_score REAL,
    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE INDEX IF NOT EXISTS idx_prediction_runs_target_date ON prediction_runs(target_date);
CREATE INDEX IF NOT EXISTS idx_prediction_runs_model ON prediction_runs(model_name, model_version);
CREATE INDEX IF NOT EXISTS idx_prediction_runs_status ON prediction_runs(status);

-- STEP120: race results and payouts
CREATE TABLE IF NOT EXISTS race_results (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    race_id INTEGER NOT NULL,
    result_status TEXT NOT NULL DEFAULT 'official' CHECK (result_status IN ('pending', 'official', 'cancelled', 'no_contest')),
    first_place INTEGER,
    second_place INTEGER,
    third_place INTEGER,
    winning_method TEXT,
    decided_at TEXT,
    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TEXT,
    UNIQUE(race_id),
    FOREIGN KEY (race_id) REFERENCES races(id)
);

CREATE INDEX IF NOT EXISTS idx_race_results_race_id ON race_results(race_id);
CREATE INDEX IF NOT EXISTS idx_race_results_status ON race_results(result_status);

CREATE TABLE IF NOT EXISTS payouts (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    race_id INTEGER NOT NULL,
    bet_type TEXT NOT NULL CHECK (bet_type IN ('trifecta', 'trio', 'exacta', 'quinella', 'wide', 'win', 'place')),
    ticket TEXT NOT NULL,
    payout_yen INTEGER NOT NULL DEFAULT 0 CHECK (payout_yen >= 0),
    popularity INTEGER,
    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
    UNIQUE(race_id, bet_type, ticket),
    FOREIGN KEY (race_id) REFERENCES races(id)
);

CREATE INDEX IF NOT EXISTS idx_payouts_race_id ON payouts(race_id);
CREATE INDEX IF NOT EXISTS idx_payouts_bet_type ON payouts(bet_type);
CREATE INDEX IF NOT EXISTS idx_payouts_ticket ON payouts(ticket);
